interface User {
  name: string
  age: number
}

function greet(user: User) {
  return `Привет, ${user.name}! Тебе ${user.age}`
}

greet({ name: 'Алекс', age: 25 })           // ✅
greet({ name: 'Алекс', age: 25, role: 'dev' }) // ❌ Excess property

function format(value: string | number): string {
  // value: string | number

  if (typeof value === 'string') {
    // value: string — TypeScript сузил тип
    return value.toUpperCase()
  }

  // value: number — string исключён
  return value.toFixed(2)
}

type Shape =
  | { kind: 'circle'; radius: number }
  | { kind: 'square'; side: number }

function area(shape: Shape): number {
  switch (shape.kind) {
    case 'circle':
      return Math.PI * shape.radius ** 2
    case 'square':
      return shape.side ** 2
    default:
      const _: never = shape
      return _
  }
}

// TypeScript (исходный код)
interface User {
  name: string
  age: number
}
const user: User = { name: 'Алекс', age: 25 }

